questions = [
    {"q": "2 + 3 = ?", "a": "5"},
    {"q": "Python dùng print để làm gì?", "a": "hiển thị"}
]
score = 0
for item in questions:
    answer = input(item["q"] + " ")
    if answer.strip().lower() == item["a"]:
        score += 1
print("Điểm:", score)

